'use client'

import {
  ThemeProvider as NextThemesProvider,
  type ThemeProviderProps
} from 'next-themes'

function ThemeProvider({ children, ...props }: ThemeProviderProps) {
  return (
    <NextThemesProvider
      attribute="class"
      defaultTheme="light"
      enableSystem
      disableTransitionOnChange
      {...props}
    >
      {children}
    </NextThemesProvider>
  )
}

export { ThemeProvider, type ThemeProviderProps }
